f not result_file.exists():\n69\t        scores[\"file_created\"] = 0.0\n70\t        scores[\"valid_format\"] = 0.0\n71\t        scores[\"date_order\"] = 0.0\n72\t        scores[\"volume_baseline\"] = 0.0\n73\t        scores[\"drawdown_checked\"] = 0.0\n74\t        return scores\n75\t\n76\t    scores[\"file_created\"] = 1.0\n77\t    content = result_file.read_text().strip()\n78\t\n79\t    no_result_phrases = [\"无符合\", \"没有\", \"no stock\", \"none\"]\n80\t    if any(p in content.lower() for p in no_result_phrases):\n81\t        scores[\"valid_format\"] = 1.0\n82\t        scores[\"date_order\"] = 1.0\n83\t    else:\n84\t        lines = [l.strip() for l in content.splitlines()\n85\t                 if l.strip() and not l.startswith(\"#\") and \"代码\" not in l]\n86\t        has_dates = bool(re.search(r'\\d{4}-\\d{2}-\\d{2}', content))\n87\t        has_code = bool(re.search(r'3\\d{5}', content))\n88\t        scores[\"valid_format\"] = 1.0 if (has_code and has_dates) else (0.5 if has_code else 0.0)\n89\t\n90\t        # Check date order: contraction_end < breakout_date\n91\t        date_sets = []\n92\t        for line in lines:\n93\t            dates = re.findall(r'\\d{4}-\\d{2}-\\d{2}', line)\n94\t            if len(dates) >= 3:\n95\t                try:\n96\t                    d1 = datetime.strptime(dates[0], \"%Y-%m-%d\")\n97\t                    d2 = datetime.strptime(dates[1], \"%Y-%m-%d\")\n98\t                    d3 = datetime.strptime(dates[2], \"%Y-%m-%d\")\n99\t                    date_sets.append(d1 < d2 < d3)\n100\t                except:\n101\t                    pass\n102\t        scores[\"date_order\"] = 1.0 if all(date_sets) and len(date_sets) > 0 else (0.5 if len(date_sets) > 0 else 0.0)\n103\t\n104\t    transcript_str = str(transcript).lower()\n105\t    scores[\"volume_baseline\"] = 1.0 if any(kw in transcript_str for kw in\n106\t        [\"60日均量\", \"60.*mean.*vol\", \"volume.*60\", \"均量\", \"avg.*vol\"]) else 0.0\n107\t    scores[\"drawdown_checked\"] =